// Parse CSV or JSON array returned by ScraperCity Maps download
// The download endpoint returns a JSON array of business objects
const raw = $input.first().json;

let businesses = [];

// Handle both array response and nested data
if (Array.isArray(raw)) {
  businesses = raw;
} else if (Array.isArray(raw.data)) {
  businesses = raw.data;
} else if (typeof raw === 'string') {
  // Basic CSV parse -- split on newlines, first row is header
  const lines = raw.trim().split('\n');
  const headers = lines[0].split(',').map(h => h.replace(/"/g, '').trim());
  businesses = lines.slice(1).map(line => {
    const vals = line.split(',');
    const obj = {};
    headers.forEach((h, i) => {
      obj[h] = (vals[i] || '').replace(/"/g, '').trim();
    });
    return obj;
  });
}

// Normalize fields and keep only records with a website
const cleaned = [];
const seen = new Set();

for (const biz of businesses) {
  const name = biz.name || biz.title || biz.businessName || '';
  const website = biz.website || biz.url || biz.websiteUrl || '';
  const phone = biz.phone || biz.phoneNumber || '';
  const address = biz.address || biz.fullAddress || '';
  const city = biz.city || '';

  if (!name || !website) continue;

  // Extract domain from website
  let domain = '';
  try {
    const url = new URL(website.startsWith('http') ? website : 'https://' + website);
    domain = url.hostname.replace(/^www\./, '');
  } catch (e) {
    domain = website.replace(/^https?:\/\/(www\.)?/, '').split('/')[0];
  }

  if (!domain || seen.has(domain)) continue;
  seen.add(domain);

  // Try to split name into first/last for email finder
  const nameParts = name.trim().split(' ');
  const firstName = nameParts[0] || 'Owner';
  const lastName = nameParts.slice(1).join(' ') || '';

  cleaned.push({
    json: {
      businessName: name,
      website,
      domain,
      phone,
      address,
      city,
      firstName,
      lastName
    }
  });
}

return cleaned;

// Build contacts array for ScraperCity email-finder from current batch
const items = $input.all();

const contacts = items.map(item => ({
  first_name: item.json.firstName || 'Owner',
  last_name: item.json.lastName || '',
  domain: item.json.domain
}));

// Also keep original business data to merge back later
return [{
  json: {
    contacts,
    originalItems: items.map(i => i.json)
  }
}];

// Merge email finder results back with original business records
const emailResults = $input.first().json;
const originalItems = JSON.parse($('Store Email Finder Run ID').item.json.originalItems || '[]');

let emailList = [];

if (Array.isArray(emailResults)) {
  emailList = emailResults;
} else if (Array.isArray(emailResults.data)) {
  emailList = emailResults.data;
} else if (Array.isArray(emailResults.contacts)) {
  emailList = emailResults.contacts;
}

// Build a lookup map by domain
const emailByDomain = {};
for (const record of emailList) {
  const domain = record.domain || record.company_domain || '';
  const email = record.email || record.emailAddress || '';
  if (domain && email) {
    emailByDomain[domain] = email;
  }
}

// Merge
const merged = [];
for (const biz of originalItems) {
  const email = emailByDomain[biz.domain] || '';
  if (!email) continue; // skip businesses where no email was found
  merged.push({
    json: {
      ...biz,
      email
    }
  });
}

return merged;
